mapper.select:
SELECT h.EMP_CODE AS empCode, h.EMP_NAME AS empName, h.DEPT_CODE AS deptCode, d.DEPT_NAME AS deptName, ISNULL(s.SHIFT_CODE, '') AS workPlanCode, ISNULL(s.SHIFT_NAME, '미설정') AS workPlanName, ISNULL(s.WORK_DAY_TYPE, 'WORK') AS workDayType, r.REQUEST_ID AS requestId, r.REQUEST_WORK_CODE AS requestWorkCode, r.REASON AS reason, r.START_TIME AS startTime, r.END_TIME AS endTime, r.STATUS AS status, r.REQUESTER_CODE AS requesterCode, re.EMP_NAME AS requesterName FROM HRIMASTER01 h LEFT JOIN ORGDEPTMASTER01 d ON h.COMPANY = d.COMPANY AND h.DEPT_CODE = d.DEPT_CODE LEFT JOIN HRTWORKPATTERNMASTER01 pm ON d.COMPANY = pm.COMPANY AND d.WORK_PATTERN_CODE = pm.WORK_PATTERN_CODE LEFT JOIN HRTWORKPATTERNDETAIL01 pd ON pm.COMPANY = pd.COMPANY AND pm.WORK_PATTERN_CODE = pd.WORK_PATTERN_CODE AND pd.SEQ = ( (DATEDIFF(DAY, pm.START_DATE, CAST(#{workDate} AS DATE)) % pm.CYCLE_COUNT + pm.CYCLE_COUNT) % pm.CYCLE_COUNT + 1 ) LEFT JOIN HRTSHIFTMASTER01 s ON pd.COMPANY = s.COMPANY AND pd.SHIFT_CODE = s.SHIFT_CODE LEFT JOIN HRTATTREQ01 r ON h.COMPANY = r.COMPANY AND h.EMP_CODE = r.EMP_CODE AND r.WORK_DATE = CAST(#{workDate} AS DATE) AND r.REQUEST_CATEGORY = #{requestCategory} LEFT JOIN HRIMASTER01 re ON r.COMPANY = re.COMPANY AND r.REQUESTER_CODE = re.EMP_CODE WHERE h.COMPANY = #{company} AND h.DEPT_CODE = #{deptCode} AND h.RETIRE_DATE IS NULL
AND h.EMP_CODE = #{loginEmpCode}
AND s.WORK_DAY_TYPE IN ('OFF', 'HOLIDAY')
AND (s.WORK_DAY_TYPE IS NULL OR s.WORK_DAY_TYPE NOT IN ('OFF', 'HOLIDAY'))
AND h.EMP_CODE = #{empCode}
AND s.SHIFT_CODE = #{workPlanFilter}
ORDER BY h.EMP_CODE

SELECT DEPT_LEADER
FROM ORGDEPTMASTER01
WHERE COMPANY = #{company}
  AND DEPT_CODE = #{deptCode}
